set-amount.expression:
(function(){
      var input=document.querySelector('input[inputmode="decimal"]');
      if(!input) return JSON.stringify({filled:false,error:'no decimal input'});
      input.focus();
      var setter=Object.getOwnPropertyDescriptor(HTMLInputElement.prototype,'value')?.set;
      if(setter){ setter.call(input,'{{amount}}'); } else { input.value='{{amount}}'; }
      input.dispatchEvent(new Event('input',{bubbles:true}));
      input.dispatchEvent(new Event('change',{bubbles:true}));
      return JSON.stringify({filled:true,value:input.value});
    })()

wait-summary.expression:
(function(){
    function textById(id){ return (document.querySelector('[data-testid="'+id+'"]')?.textContent || '').trim(); }
    const margin = textById('perps-order-summary-margin-required');
    const liquidation = textById('perps-order-summary-liquidation-price');
    const fees = textById('perps-order-summary-estimated-fees');
    const feeReady = !!fees && fees !== '-' && fees !== '$0' && fees !== '$0.00';
    return JSON.stringify({ready: !!margin && margin !== '-' && !!liquidation && liquidation !== '-' && feeReady});
  })()

extract.expression:
(function(){
    function text(el){ return (el?.textContent || '').trim(); }
    function textById(id){ return (document.querySelector('[data-testid="'+id+'"]')?.textContent || '').trim() || null; }
    function lines(el){ return (el?.innerText || el?.textContent || '').split(/\n+/).map(function(s){return s.trim();}).filter(Boolean); }
    function labelValue(label){
      const candidates = Array.from(document.querySelectorAll('p,span,div')).filter(function(el){ return text(el)===label; });
      for (const el of candidates){
        let cur = el.parentElement;
        for(let i=0;i<4 && cur;i++,cur=cur.parentElement){
          const l = lines(cur);
          if(l.includes(label) && l.length<=6){
            const vals = l.filter(function(x){ return x!==label; });
            if(vals.length) return vals[vals.length-1];
          }
        }
      }
      return null;
    }
    return JSON.stringify({symbol:'{{symbol}}',screen:'order_entry',price:text(document.querySelector('[data-testid="perps-order-entry-price"]')),change:text(document.querySelector('[data-testid="perps-order-entry-change"]')),margin:textById('perps-order-summary-margin-required') || labelValue('Margin'),liquidationPrice:textById('perps-order-summary-liquidation-price') || labelValue('Liquidation price'),fees:textById('perps-order-summary-estimated-fees') || labelValue('Fees')});
  })()
